SELECT Max(oMonetaryAmount.`HASAMOUNT`) AS AggResult1 FROM FIBEN.`LISTEDSECURITY` oListedSecurity INNER JOIN FIBEN.`MONETARYAMOUNT` oMonetaryAmount ON oListedSecurity.`HASLASTTRADEDVALUE`=oMonetaryAmount.`MONETARYAMOUNTID` INNER JOIN FIBEN.`SECURITY` Security1 ON oListedSecurity.`LISTEDSECURITYID`=Security1.`SECURITYID` INNER JOIN FIBEN.`FINANCIALMARKET` oFinancialMarket ON Security1.`ISTRADEDON`=oFinancialMarket.`FINANCIALMARKETID` WHERE oFinancialMarket.`HASNAME` = 'NYSE'